import{_ as a,c as t,o as e,b as m}from"./app.1117c437.js";const l='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 12-14","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 12-14","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-03T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/12-14/index.md"}',s={},o=m('<div class="stanza"><a href="#s3.12" id="s3.12" class="num">3.12</a><div class="sans"><p>\u0905\u0938\u094D\u092F \u091A\u2014</p><blockquote><p><strong>\u0927\u0940\u0935\u0936\u093E\u0924\u094D\u0938\u0924\u094D\u0924\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u093F\u0903\u0965\u0967\u0968\u0965</strong></p></blockquote><p>\u0927\u0940\u0903 \u0924\u093E\u0924\u094D\u0924\u094D\u0935\u093F\u0915\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u0935\u093F\u0936\u093E\u0930\u0926\u093E (...\u0935\u093F\u0936\u093E\u0926\u093E) \u0927\u093F\u0937\u0923\u093E \u0924\u0926\u094D\u0935\u0936\u093E\u0924\u094D\u0938\u0924\u094D\u0924\u094D\u0935\u0938\u094D\u092F \u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0938\u094D\u092F\u093E\u0928\u094D\u0924\u0930\u092A\u0930\u093F\u0938\u094D\u092A\u0928\u094D\u0926\u0938\u094D\u092F \u0938\u093F\u0926\u094D\u0927\u093F\u0930\u092D\u093F\u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u093F\u0964 \u0928\u093E\u091F\u094D\u092F\u0947 \u091A \u0938\u093E\u0924\u094D\u0924\u094D\u0935\u093F\u0915\u093E\u092D\u093F\u0928\u092F\u0938\u093F\u0926\u094D\u0927\u093F\u0930\u094D\u092C\u0941\u0926\u094D\u0927\u093F\u0915\u094C\u0936\u0932\u093E\u0926\u0947\u0935 \u0932\u092D\u094D\u092F\u0924\u0947\u0965\u0967\u0968\u0965</p></div><hr><div class="trans"><p>Asya ca\u2014</p><blockquote><p><strong>Dh\u012Bva\u015B\u0101tsattvasiddhi\u1E25||12||</strong></p></blockquote><p>Dh\u012B\u1E25 t\u0101ttvikasvar\u016Bpavimar\u015Banavi\u015B\u0101rad\u0101 (...vi\u015B\u0101d\u0101) dhi\u1E63a\u1E47\u0101 tadva\u015B\u0101tsattvasya sphuratt\u0101tmana\u1E25 s\u016Bk\u1E63masy\u0101ntaraparispandasya siddhirabhivyaktirbhavati| N\u0101\u1E6Dye ca s\u0101ttvik\u0101bhinayasiddhirbuddhikau\u015Bal\u0101deva labhyate||12||</p></div><hr><p>\u0418 <em>(ca)</em> \u0443 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>\u2014</p><blockquote><p><strong>\u0421 \u043F\u043E\u043C\u043E\u0449\u044C\u044E <em>(va\u015B\u0101t)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(dh\u012B)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(siddhi\u1E25)</em> \u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0435\u0439, \u0442\u043E\u043D\u043A\u043E\u0439 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sattva)</em>||12||</strong></p></blockquote><p>Dh\u012B <em>(dh\u012B)</em> [\u2014 \u044D\u0442\u043E] \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 <em>(dhi\u1E63a\u1E47\u0101)</em>, \u043E\u043F\u044B\u0442\u043D\u044B\u0439 <em>(vi\u015B\u0101rad\u0101)</em>, [\u0438\u043B\u0438] \u0438\u0441\u043A\u0443\u0441\u043D\u044B\u0439 <em>(vi\u015B\u0101d\u0101)</em> \u0432 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0438 <em>(vimar\u015Bana)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 <em>(t\u0101ttvika)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F <em>(va\u015B\u0101t)</em> \u044D\u0442\u043E\u043C\u0443 [\u0432\u044B\u0441\u0448\u0435\u043C\u0443 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u043C\u0443 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443] <em>(tad)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> siddhi <em>(siddhi\u1E25)</em>, [\u0438\u043B\u0438] \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 --\u0442.\u0435. \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0449\u0435\u0435\u0441\u044F \u044F\u0432\u043D\u044B\u043C-- <em>(abhivyakti\u1E25)</em> \u0421\u0430\u0442\u0442\u0432\u044B (Sattva) <em>(sattvasya)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0442\u043E\u043D\u043A\u043E\u0439 <em>(s\u016Bk\u1E63masya)</em> [\u0438] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(\u0101ntara)</em> \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0438 --parispanda-- <em>(parispandasya)</em>, \u0447\u044C\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(\u0101tmana\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] Sphuratt\u0101 --\u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0435\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0435 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435-- <em>(sphuratt\u0101)</em>|</p><p>\u0412 \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u0435 <em>(n\u0101\u1E6Dye)</em> \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em>, siddhi, \u0438\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E <em>(siddhi\u1E25)</em> \u0432 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0438 <em>(abhinaya)</em> Sattva, \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u044F/\u0447\u0443\u0432\u0441\u0442\u0432\u0430 <em>(s\u0101ttvika)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F <em>(labhyate)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0447\u0435\u0440\u0435\u0437 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u043E <em>(kau\u015Bal\u0101t)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(buddhi)</em><sup>1</sup>||12||</p><hr><ol><li>\u041F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E: \u0417\u0434\u0435\u0441\u044C \u0442\u0435\u0440\u043C\u0438\u043D &quot;Sattva&quot; \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u043A \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u043E\u0439 Gu\u1E47a, \u0438\u043B\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0443 \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438 (Prak\u1E5Bti) . \u0421\u0435\u0439\u0447\u0430\u0441 \u043C\u0443\u0434\u0440\u0435\u0446 \u043F\u043E\u0441\u0442\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043B \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u044E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E n\u0101\u1E6Dya, \u0438\u043B\u0438 \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u044B: \u0412 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432 \u0419\u043E\u0433\u0435 \u0435\u0441\u0442\u044C siddhi, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 Sattva (\u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0435\u0439, \u0442\u043E\u043D\u043A\u043E\u0439 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C dh\u012B (\u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430), \u0442\u043E \u0432 \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u0435 \u0438\u043C\u0435\u0435\u0442\u0441\u044F siddhi, \u0438\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E \u0432 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0438 Sattva (\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u044F, \u0438\u043B\u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0430) \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430/\u0438\u0441\u043A\u0443\u0441\u043D\u043E\u0441\u0442\u0438 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 (buddhi), \u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u0442\u0430\u043B\u0430\u043D\u0442. \u0422\u0435\u0440\u043C\u0438\u043D &quot;buddhi&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043D\u043E\u043D\u0438\u043C\u043E\u043C \u0441 &quot; \u0927\u0940&quot; - &quot;dh\u012B&quot;, \u043D\u043E \u0432 \u043E\u0431\u044B\u0447\u043D\u043E\u043C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E, \u0442.\u0435. \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430. \u0422\u0435\u043F\u0435\u0440\u044C \u044D\u0442\u043E \u043F\u043E\u043D\u044F\u0442\u043D\u043E.</li></ol></div><div class="stanza"><a href="#s3.13" id="s3.13" class="num">3.13</a><div class="sans"><p>\u090F\u0935\u0902 \u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u0915\u0938\u0924\u094D\u0924\u094D\u0935\u093E\u0938\u093E\u0926\u0928\u093E\u0926\u0947\u0935\u093E\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903\u2014</p><blockquote><p><strong>\u0938\u093F\u0926\u094D\u0927\u0903 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u092D\u093E\u0935\u0903\u0965\u0967\u0969\u0965</strong></p></blockquote><p>\u0938\u093F\u0926\u094D\u0927\u0903 \u0938\u092E\u094D\u092A\u0928\u094D\u0928\u0903 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u092D\u093E\u0935\u0903 \u0938\u0939\u091C\u091C\u094D\u091E\u0924\u094D\u0935\u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u093E\u0924\u094D\u092E\u0915\u092E\u0936\u0947\u0937\u0935\u093F\u0936\u094D\u0935\u0935\u0936\u0940\u0915\u093E\u0930\u093F \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u092E\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0936\u094D\u0930\u0940\u0928\u093E\u0925\u092A\u093E\u0926\u0948\u0903</p><blockquote><p>\u0936\u094D\u0930\u092F\u0947\u0924\u094D\u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0936\u0915\u094D\u0924\u093F\u0902 \u0938\u094D\u0935\u093E\u0902 \u0938\u093E \u0936\u094D\u0930\u0940\u0915\u093E\u0932\u0940 \u092A\u0930\u093E \u0915\u0932\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>\u0938\u0930\u094D\u0935\u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0928\u093F \u092D\u0942\u0924\u093E\u0928\u093F \u0935\u0930\u094D\u0923\u093E \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0936\u094D\u091A \u092F\u0947 \u0938\u094D\u092E\u0943\u0924\u093E\u0903\u0964<br> \u0928\u093F\u0924\u094D\u092F\u0902 \u0924\u0938\u094D\u092F \u0935\u0936\u093E\u0938\u094D\u0924\u0947 \u0935\u0948 \u0936\u093F\u0935\u092D\u093E\u0935\u0928\u092F\u093E\u0928\u092F\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u0969\u0965</p></div><hr><div class="trans"><p>Eva\u1E41 sphuratt\u0101tmakasattv\u0101s\u0101dan\u0101dev\u0101sya yogina\u1E25\u2014</p><blockquote><p><strong>Siddha\u1E25 svatantrabh\u0101va\u1E25||13||</strong></p></blockquote><p>Siddha\u1E25 sampanna\u1E25 svatantrabh\u0101va\u1E25 sahajaj\xF1atvakart\u1E5Btv\u0101tmakama\u015Be\u1E63avi\u015Bvava\u015B\u012Bk\u0101ri sv\u0101tantryam| Yadukta\u1E41 \u015Br\u012B\u015Br\u012Bn\u0101thap\u0101dai\u1E25</p><blockquote><p>\u015Arayetsv\u0101tantrya\u015Bakti\u1E41 sv\u0101\u1E41 s\u0101 \u015Br\u012Bk\u0101l\u012B par\u0101 kal\u0101|</p></blockquote><p>iti| \u015Ar\u012Bsvacchande&#39;pi</p><blockquote><p>Sarvatattv\u0101ni bh\u016Bt\u0101ni var\u1E47\u0101 mantr\u0101\u015Bca ye sm\u1E5Bt\u0101\u1E25|<br> Nitya\u1E41 tasya va\u015B\u0101ste vai \u015Bivabh\u0101vanay\u0101nay\u0101||</p></blockquote><p>iti||13||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043F\u0443\u0442\u0435\u043C \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F <em>(\u0101s\u0101dan\u0101t eva)</em> Sattva <em>(sattva)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 <em>(\u0101tmaka)</em> Sphuratt\u0101 --\u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0435\u0433\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sphuratt\u0101)</em>, [\u0432 \u0441\u043B\u0443\u0447\u0430\u0435] \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> Yog\u012B <em>(yogina\u1E25)</em>\u2014</p><blockquote><p><strong>\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va\u1E25)</em> \u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u0438 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(svatantra)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E <em>(siddha\u1E25)</em>||13||</strong></p></blockquote><p>Siddha <em>(siddha\u1E25)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0439, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u044B\u0439&quot; [\u0438 \u0442\u0430\u043A \u0434\u0430\u043B\u0435\u0435] <em>(sampanna\u1E25)</em>, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A] svatantrabh\u0101va <em>(svatantra-bh\u0101va\u1E25)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0421\u0432\u043E\u0431\u043E\u0434\u0443 <em>(sv\u0101tantryam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u043E\u0434\u0447\u0438\u043D\u044F\u0435\u0442 \u0432\u0441\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(a\u015Be\u1E63a-vi\u015Bva-va\u015B\u012Bk\u0101ri)</em> [\u0438] \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmakam)</em> \u0435\u0441\u0442\u044C \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sahaja)</em> \u0417\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1atva)</em> [\u0438] \u0414\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(kart\u1E5Btva)</em>|</p><p>\u042D\u0442\u043E \u0436\u0435 <em>(yad)</em> [\u0431\u044B\u043B\u043E] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u044B\u043C N\u0101thap\u0101da <em>(\u015Br\u012B\u015Br\u012B-n\u0101thap\u0101dai\u1E25)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0442\u044C <em>(\u015Brayet)</em> \u043A \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sv\u0101m)</em> \u0421\u0438\u043B\u0435 <em>(\u015Baktim)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(sv\u0101tantrya)</em>. \u041E\u043D\u0430 --\u0442\u0430\u043A\u0430\u044F \u0421\u0438\u043B\u0430-- <em>(s\u0101)</em> [\u0435\u0441\u0442\u044C] \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u0430\u044F K\u0101l\u012B <em>(\u015Br\u012B-k\u0101l\u012B)</em>, \u0412\u044B\u0441\u0448\u0430\u044F <em>(par\u0101)</em> Kal\u0101 --\u0442.\u0435. \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430-- <em>(kal\u0101... iti)</em><sup>1</sup>&quot;|</p></blockquote><p>\u0412 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012Bsvacchande)</em> \u044D\u0442\u043E \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u0412\u0441\u0435 <em>(sarva)</em> \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, 36 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439-- <em>(tattv\u0101ni)</em>, \u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(bh\u016Bt\u0101ni)</em>, \u0431\u0443\u043A\u0432\u044B <em>(var\u1E47\u0101\u1E25)</em> \u0438 <em>(ca)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantr\u0101\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ye)</em> \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B <em>(sm\u1E5Bt\u0101\u1E25)</em>; [\u0432\u0441\u0435] \u043E\u043D\u0438 <em>(te)</em> \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u043E\u0434\u0447\u0438\u043D\u0435\u043D\u044B <em>(nityam... va\u015B\u0101\u1E25)</em> \u0435\u043C\u0443 --\u0442.\u0435. Yog\u012B-- <em>(tasya)</em> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(vai)</em>, \u0447\u0435\u0440\u0435\u0437 \u044D\u0442\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 <em>(bh\u0101vanay\u0101 anay\u0101)</em> \u015Aiva <em>(\u015Biva... iti)</em>&quot;|<br> [\u0421\u043C. VII, 245 \u0432 Svacchandatantra]</p></blockquote><p>||13||</p><hr><ol><li>\u0422\u0435\u0440\u043C\u0438\u043D Kal\u0101 \u2014 \u044D\u0442\u043E \u0435\u0449\u0435 \u043E\u0434\u0438\u043D \u0442\u0435\u0440\u043C\u0438\u043D, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043B\u044E\u0431\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0434\u043F\u043E\u0447\u0435\u043B \u0431\u044B \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043D\u0435 \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u043C. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 &quot;\u043C\u043D\u043E\u0433\u043E\u0441\u043B\u043E\u0432\u043D\u044B\u0445&quot; \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 \u0441\u043B\u0438\u0448\u043A\u043E\u043C \u0432\u0435\u043B\u0438\u043A\u043E. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0440\u044F\u0434 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0445 \u0438\u0437 \u043A\u043E\u0440\u043D\u0435\u0439. \u041D\u043E \u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442, \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 &quot;\u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430&quot; \u0431\u043E\u043B\u0435\u0435, \u0447\u0435\u043C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E. \u0422\u0435\u0440\u043C\u0438\u043D Par\u0101 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0437\u0434\u0435\u0441\u044C &quot;\u0412\u044B\u0441\u0448\u0430\u044F&quot;, \u043D\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u0435\u043D \u0438 \u0434\u0440\u0443\u0433\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0439 \u0438\u0437 \u043A\u043E\u0440\u043D\u044F. \u041E \u0413\u043E\u0441\u043F\u043E\u0434\u0438! \u0411\u0443\u0434\u044C \u043C\u0438\u043B\u043E\u0441\u0442\u0438\u0432 \u043A \u043D\u0430\u043C, \u043F\u0440\u043E\u0441\u0442\u044B\u043C \u0441\u043C\u0435\u0440\u0442\u043D\u044B\u043C! \u0425\u043E\u0440\u043E\u0448\u043E, \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0439\u0442\u0435 \u0447\u0438\u0442\u0430\u0442\u044C.</li></ol></div><div class="stanza"><a href="#s3.14" id="s3.14" class="num">3.14</a><div class="sans"><p>\u090F\u0937 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u092D\u093E\u0935\u094B\u093D\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u092F\u0925\u093E \u0924\u0924\u094D\u0930 \u0924\u0925\u093E\u0928\u094D\u092F\u0924\u094D\u0930\u0965\u0967\u096A\u0965</strong></p></blockquote><p>\u092F\u0924\u094D\u0930 \u0926\u0947\u0939\u0947 \u092F\u094B\u0917\u093F\u0928\u0903 \u0938\u094D\u0935\u093E\u092D\u093F\u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0930\u094D\u091C\u093E\u0924\u093E \u0924\u0924\u094D\u0930 \u092F\u0925\u093E \u0924\u0925\u093E\u0928\u094D\u092F\u0924\u094D\u0930 \u0938\u0930\u094D\u0935\u0924\u094D\u0930 \u0938\u0926\u093E\u0935\u0939\u093F\u0924\u0938\u094D\u092F \u0938\u093E \u092D\u0935\u0924\u093F\u0964 \u092F\u0925\u094B\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0936\u094D\u091A\u0948\u0935 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0903 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u094B \u0935\u093F\u091A\u0930\u0947\u0924\u094D\u0938\u0926\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0938\u094D\u092A\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>\u0932\u092D\u0924\u0947 \u0924\u0924\u094D\u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0947\u0928 \u092A\u0930\u0940\u0915\u094D\u0937\u094D\u092F\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u092E\u093E\u0926\u0930\u093E\u0924\u094D\u0964<br> \u092F\u0924\u0903 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0924\u093E \u0924\u0938\u094D\u092F \u0938\u0930\u094D\u0935\u0924\u094D\u0930\u0947\u092F\u092E\u0915\u0943\u0924\u094D\u0930\u093F\u092E\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u096A\u0965</p></div><hr><div class="trans"><p>E\u1E63a svatantrabh\u0101vo&#39;sya\u2014</p><blockquote><p><strong>Yath\u0101 tatra tath\u0101nyatra||14||</strong></p></blockquote><p>Yatra dehe yogina\u1E25 sv\u0101bhivyaktirj\u0101t\u0101 tatra yath\u0101 tath\u0101nyatra sarvatra sad\u0101vahitasya s\u0101 bhavati| Yathokta\u1E41 \u015Br\u012Bsvacchande</p><blockquote><p>Svacchanda\u015Bcaiva svacchanda\u1E25 svacchando vicaretsad\u0101|</p></blockquote><p>iti| \u015Ar\u012Bspande&#39;pi</p><blockquote><p>Labhate tatprayatnena par\u012Bk\u1E63ya\u1E41 tattvam\u0101dar\u0101t|<br> Yata\u1E25 svatantrat\u0101 tasya sarvatreyamak\u1E5Btrim\u0101||</p></blockquote><p>iti||14||</p></div><hr><p>\u0415\u0433\u043E <em>(asya)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(e\u1E63a\u1E25... bh\u0101va\u1E25)</em> \u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u0438 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(svatantra)</em><sup>1</sup>\u2014</p><blockquote><p><strong>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0442\u0430\u043C <em>(tatra)</em>, \u0442\u0430\u043A \u0438 <em>(tath\u0101)</em> \u0433\u0434\u0435-\u043B\u0438\u0431\u043E \u0435\u0449\u0435 <em>(anyatra)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, &quot;\u0442\u0430\u043A \u0436\u0435 \u043A\u0430\u043A \u044D\u0442\u043E\u0442 \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u0439 Yog\u012B \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0421\u0432\u043E\u0431\u043E\u0434\u0443 \u0432 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0442\u0435\u043B\u0435, \u043E\u043D \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0436\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u044D\u0442\u043E \u0432 \u043B\u044E\u0431\u043E\u043C \u0434\u0440\u0443\u0433\u043E\u043C \u043C\u0435\u0441\u0442\u0435&quot;; \u0442\u0430\u043A\u043E\u0432 \u0441\u043C\u044B\u0441\u043B]||14||</strong></p></blockquote><p>\u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435, \u043A\u0430\u043A <em>(yath\u0101)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(sva)</em> [\u0441\u0438\u043B\u0430] \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 <em>(abhivyakti\u1E25)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(j\u0101t\u0101)</em> \u0442\u0430\u043C <em>(tatra)</em> \u2014\u0432 \u044D\u0442\u043E\u043C \u0442\u0435\u043B\u0435 <em>(yatra dehe)</em> Yog\u012B <em>(v\u0101hin\u012Bn\u0101m)</em>\u2014, \u0442\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tath\u0101)</em> \u044D\u0442\u0430 [\u0441\u0438\u043B\u0430 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438] <em>(ap\u0101na)</em> \u0432\u0441\u0435\u0433\u0434\u0430 \u0431\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E [Yog\u012B] <em>(sad\u0101-avahitasya)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0432 \u043B\u044E\u0431\u043E\u043C \u0434\u0440\u0443\u0433\u043E\u043C \u043C\u0435\u0441\u0442\u0435 <em>(anyatra)</em> [\u0442\u0430\u043A\u0436\u0435], \u0442.\u0435. \u0432\u0435\u0437\u0434\u0435 <em>(sarvatra)</em>|</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> [\u0431\u044B\u043B\u043E] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;[\u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C Yog\u012B-s] \u0431\u0440\u043E\u0434\u0438\u0442 <em>(vicaret)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C <em>(svacchanda\u1E25 ca eva svacchanda\u1E25 svacchanda\u1E25)</em>, [\u0431\u0443\u0434\u044C \u0442\u043E \u0432 \u043D\u0430\u0447\u0430\u043B\u0435, \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0438\u043B\u0438 \u0432 \u043A\u043E\u043D\u0446\u0435]<sup>2</sup>&quot;||<br> [\u0421\u043C. VII, 260 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande)</em> [\u0431\u044B\u043B\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0443\u043A\u0430\u0437\u0430\u043D\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u0422\u043E\u0442 <em>(tad)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F [\u0421\u043F\u0430\u043D\u0434\u044B] <em>(tattvam)</em> \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0438\u0437\u0443\u0447\u0435\u043D <em>(par\u012Bk\u1E63yam)</em> \u0441 \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u043D\u043E\u0441\u0442\u044C\u044E <em>(prayatnena)</em> [\u0438] \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435\u043C <em>(\u0101dar\u0101t)</em>, [\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u044D\u0442\u0430 \u0433\u0440\u0443\u043F\u043F\u0430 \u043E\u0440\u0433\u0430\u043D\u043E\u0432, \u0438\u043B\u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 --\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, \u044D\u0433\u043E, \u0443\u043C, \u0441\u0438\u043B\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0441\u0438\u043B\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F--, [\u0431\u0443\u0434\u0443\u0447\u0438] \u043D\u0435\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u043D\u043E\u0439, [\u0432\u0435\u0434\u0435\u0442 \u0441\u0435\u0431\u044F] \u043A\u0430\u043A [\u0435\u0441\u043B\u0438 \u0431\u044B \u043E\u043D\u0430 \u0431\u044B\u043B\u0430] \u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u0441\u0430\u043C\u0430 \u043F\u043E \u0441\u0435\u0431\u0435, [\u0438] \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 [Kara\u1E47e\u015Bvar\u012B-s, \u0438\u043B\u0438 \u0431\u043E\u0433\u0438\u043D\u044C \u0447\u0443\u0432\u0441\u0442\u0432]] \u0432\u0445\u043E\u0434\u0438\u0442 <em>(labhate)</em> [\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F &quot;Prav\u1E5Btti&quot; --\u0443\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F \u043A \u0432\u043D\u0435\u0448\u043D\u0438\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C--, &quot;Sthiti&quot; --\u0442.\u0435. \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u044D\u0442\u0438\u0445 \u0441\u0430\u043C\u044B\u0445 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u043A\u0430\u043A\u043E\u0435-\u0442\u043E \u0432\u0440\u0435\u043C\u044F-- [\u0438] &quot;Sa\u1E41h\u1E5Bti&quot; --\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u044D\u0442\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0432 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0412\u044B\u0441\u0448\u0435\u043C \u042F--], \u0432\u0432\u0438\u0434\u0443 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E <em>(yatas)</em> \u0442\u0430\u043A\u0430\u044F <em>(iyam)</em> \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(ak\u1E5Btrim\u0101)</em> \u0421\u0432\u043E\u0431\u043E\u0434\u0430 <em>(svatantrat\u0101)</em> \u042D\u0442\u043E\u0433\u043E <em>(tasya)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442] \u043F\u043E\u0432\u0441\u0435\u043C\u0435\u0441\u0442\u043D\u043E <em>(sarvatra... iti)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 7]</p></blockquote><p>||14||</p><hr><ol><li><p>\u0411\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E: \u042D\u0442\u043E <em>(e\u1E63a\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va\u1E25)</em> \u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u0438 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(svatantra)</em> \u0435\u0433\u043E --\u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u0435\u043C\u0443-- <em>(asya)</em>. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u0437\u0432\u0443\u0447\u0438\u0442 \u0441\u0442\u0440\u0430\u043D\u043D\u043E, \u044F \u0440\u0435\u0448\u0438\u043B \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u0444\u0440\u0430\u0437\u0443 \u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u043D\u044F\u0442\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C.</p></li><li><p>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u044F \u0446\u0438\u0442\u0438\u0440\u0443\u044E \u0441\u0435\u0439\u0447\u0430\u0441 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438 \u0432 \u0435\u0433\u043E Svacchandoddyota: &quot; \u0928\u093F\u0924\u094D\u092F\u092E\u093E\u0926\u093F\u092E\u0927\u094D\u092F\u093E\u0928\u094D\u0924\u0915\u094B\u091F\u093F\u0937\u094D\u0935\u092F\u0902 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u092D\u0948\u0930\u0935 \u090F\u0935 \u0938\u094D\u092B\u0941\u0930\u0928\u094D \u0938\u094D\u0925\u093F\u0924\u0903 - \u0907\u0924\u093F \u092F\u093E\u0935\u0924\u094D\u0965&quot; - &quot;Nityam\u0101dimadhy\u0101ntako\u1E6Di\u1E63vaya\u1E41 \u015Br\u012Bsvacchandabhairava eva sphuran sthita\u1E25 - iti y\u0101vat||&quot; - &quot;\u042D\u0442\u043E\u0442 \u0421\u0432\u044F\u0442\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430 (Bhairava) --\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E-- \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0441\u0438\u044F\u0442\u044C, \u0438\u043B\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E, \u0442.\u0435. \u0432 \u043D\u0430\u0447\u0430\u043B\u0435, \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435. \u0422\u0430\u043A\u043E\u0432\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435&quot;.</p></li></ol><p>\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E (Bhairava) \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F \u0432 \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435 Yog\u012B-s, \u0431\u0443\u0434\u044C \u0442\u043E \u0432 \u043D\u0430\u0447\u0430\u043B\u0435, \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0438\u043B\u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0432\u0441\u0435\u0433\u043E (\u0432 \u043F\u0440\u043E\u0448\u043B\u043E\u043C, \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0438 \u0431\u0443\u0434\u0443\u0449\u0435\u043C). \u041A\u043E\u0440\u043E\u0447\u0435, \u0442\u0430\u043A\u043E\u0439 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0443\u0435\u0442 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0421\u0432\u043E\u0431\u043E\u0434\u044B.</p><ol start="3"><li>\u0422\u0430\u043A \u043A\u0430\u043A \u0441\u0442\u0440\u043E\u0444\u0430 I, 7 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0439 \u0441 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u0439 (I, 6), \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0442\u044C \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044E\u044E \u0432 \u0441\u043A\u043E\u0431\u043A\u0438. \u041F\u0440\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u044D\u0442\u0438 \u0441\u0442\u0440\u043E\u0444\u044B (I, 6-7) \u0432 Spandak\u0101rik\u0101-s, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C, \u043E \u0447\u0435\u043C \u044F \u0433\u043E\u0432\u043E\u0440\u044E.</li></ol></div>',3),i=[o];function p(r,v,n,d,h,u){return e(),t("div",null,i)}var k=a(s,[["render",p]]);export{l as __pageData,k as default};
